-- ============================================================
-- LANGKAH 3: Preview — cek PIN yang ditemukan / tidak
-- ============================================================
SELECT t.pin, COUNT(*) AS total_scan,
  u.user_id,
  u.user_nama_depan || ' ' || u.user_nama_belakang AS nama
FROM tmp_absen_import t
LEFT JOIN users u ON u.user_pin = t.pin::text
GROUP BY t.pin, u.user_id, u.user_nama_depan, u.user_nama_belakang
ORDER BY t.pin;

-- ============================================================
-- LANGKAH 4: PIN yang TIDAK ADA di tabel users
-- ============================================================
SELECT DISTINCT t.pin, COUNT(*) AS total_scan
FROM tmp_absen_import t
LEFT JOIN users u ON u.user_pin = t.pin::text
WHERE u.user_id IS NULL
GROUP BY t.pin
ORDER BY t.pin;

-- ============================================================
-- LANGKAH 5: Cek data yang akan diimport vs yang sudah ada
-- ============================================================
SELECT
  'Sudah ada di DB (akan di-skip)'  AS status,
  COUNT(*) AS jumlah
FROM tmp_absen_import t
INNER JOIN users u ON u.user_pin = t.pin::text
WHERE EXISTS (
  SELECT 1 FROM attendances a
  WHERE a.user_id = u.user_id
    AND a.scan_time = (t.tanggal::text || ' ' || t.waktu::text || '+07:00')::timestamptz
)
UNION ALL
SELECT
  'Baru (akan diimport)',
  COUNT(*)
FROM tmp_absen_import t
INNER JOIN users u ON u.user_pin = t.pin::text
WHERE NOT EXISTS (
  SELECT 1 FROM attendances a
  WHERE a.user_id = u.user_id
    AND a.scan_time = (t.tanggal::text || ' ' || t.waktu::text || '+07:00')::timestamptz
);

-- ============================================================
-- LANGKAH 6: IMPORT — skip record yang sudah ada (WHERE NOT EXISTS)
--   Aman dijalankan berulang kali, tidak akan membuat duplikat
--   Tidak membutuhkan unique constraint di tabel attendances
-- ============================================================
INSERT INTO attendances (user_id, scan_time, status_scan)
SELECT
  u.user_id,
  (t.tanggal::text || ' ' || t.waktu::text || '+07:00')::timestamptz AS scan_time,
  NULL AS status_scan
FROM tmp_absen_import t
INNER JOIN users u ON u.user_pin = t.pin::text
WHERE NOT EXISTS (
  -- Skip jika scan_time yang sama untuk user yang sama sudah ada di DB
  SELECT 1 FROM attendances a
  WHERE a.user_id = u.user_id
    AND a.scan_time = (t.tanggal::text || ' ' || t.waktu::text || '+07:00')::timestamptz
);

-- ============================================================
-- LANGKAH 7: Laporan hasil import
-- ============================================================
SELECT 'Total baris di file'          AS keterangan, COUNT(*) AS jumlah FROM tmp_absen_import
UNION ALL
SELECT 'PIN tidak ditemukan di users', COUNT(DISTINCT t.pin)
  FROM tmp_absen_import t
  LEFT JOIN users u ON u.user_pin = t.pin::text
  WHERE u.user_id IS NULL
UNION ALL
SELECT 'Total record 1-15 Jun di DB sekarang',
  COUNT(*)
  FROM attendances
  WHERE scan_time >= '2026-06-01T00:00:00+07:00'
    AND scan_time <= '2026-06-15T23:59:59+07:00';

